#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <math.h>

int is_integer(double num) {
    return num == floor(num);
}

int main() {
    char a[100];
    scanf("%s", a);
    double b = atof(a);
    if (is_integer(b)) {
        printf("%d\n", (int)b);
    } else {
        printf("%g\n", b);
    }
    return 0;
}
